import { useEffect, useRef } from 'react';

export default function ModalConfirmacion({
  id,
  titulo,
  mensaje,
  visible,
  onCerrar,
  onConfirmar,
  textoConfirmar = 'Confirmar',
  variante = 'primary',
  mostrarCancelar = true,
}) {
  const ref = useRef(null);
  const instancia = useRef(null);

  useEffect(() => {
    if (ref.current && window.bootstrap) {
      instancia.current = window.bootstrap.Modal.getOrCreateInstance(ref.current, { backdrop: 'static' });
      const el = ref.current;
      const alOcultar = () => onCerrar?.();
      el.addEventListener('hidden.bs.modal', alOcultar);
      return () => el.removeEventListener('hidden.bs.modal', alOcultar);
    }
    return undefined;
  }, [onCerrar]);

  useEffect(() => {
    if (!instancia.current) return;
    if (visible) instancia.current.show();
    else instancia.current.hide();
  }, [visible]);

  return (
    <div className="modal fade" id={id} ref={ref} tabIndex="-1" aria-labelledby={`${id}Label`} aria-hidden="true">
      <div className="modal-dialog modal-dialog-centered">
        <div className="modal-content">
          <div className="modal-header">
            <h2 className="modal-title h5" id={`${id}Label`}>
              {titulo}
            </h2>
            <button type="button" className="btn-close" aria-label="Cerrar" onClick={onCerrar} />
          </div>
          <div className="modal-body">{mensaje}</div>
          <div className="modal-footer">
            {mostrarCancelar && (
              <button type="button" className="btn btn-outline-secondary" onClick={onCerrar}>
                Cancelar
              </button>
            )}
            <button
              type="button"
              className={`btn btn-${variante}`}
              onClick={() => {
                onConfirmar?.();
                onCerrar?.();
              }}
            >
              {textoConfirmar}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
}
